(47, 'Współrzędne środka odcinka to:', '(x₁ – x₂, y₁ – y₂)', '((x₁ + x₂)/2, (y₁ + y₂)/2)', '(x₁ + x₂, y₁ + y₂)', '(|x₁ – x₂|, |y₁ – y₂|)', 'B', 'math_cartesian_plane'),
